-- Luke Chapter 14
-- Theme: Humility, the Great Banquet, and the Cost of Discipleship
-- 35 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 14,
  'Luke 14 is set almost entirely at a Sabbath dinner in the house of a leading Pharisee (v.1). This banquet setting is not incidental — it becomes the vehicle for three interlocking teachings: a healing that provokes controversy (vv.1-6), wisdom about seating at feasts (vv.7-11), instructions for guest lists (vv.12-14), and the parable of the great supper (vv.15-24). The entire chapter wrestles with the social, economic, and spiritual dynamics of who is included and excluded, who chooses humility and who pursues honor, and what it truly means to respond to God''s invitation.' ||
  'The healing of the man with dropsy (vv.1-6) is the sixth and final Sabbath healing in Luke and the only instance of this particular condition. The Pharisees'' watchful silence (v.1) reveals a trap being set. Jesus heals without asking permission, argues from lesser to greater (rescuing an ox from a pit on the Sabbath), and leaves his opponents speechless. The parable about banquet seats (vv.7-11) observes the scramble for honor at the table and recommends the lowest seat — not as social strategy but as spiritual posture: "For whosoever exalteth himself shall be abased; and he that humbleth himself shall be exalted."' ||
  'The instruction about guest lists (vv.12-14) is radical: do not invite those who can repay you but the poor, the maimed, the lame, the blind — those who cannot. This is kingdom economy: "thou shalt be recompensed at the resurrection of the just." The parable of the great supper (vv.15-24) — triggered by a dinner guest''s pious exclamation about eating bread in the kingdom — portrays three waves of invited guests who all make excuses (land, oxen, marriage) and are replaced by street-gathered outcasts (poor, maimed, halt, blind), and then by those from the highways and hedges, filling the house for the final Gentile mission.' ||
  'The chapter''s second half (vv.25-35) steps outside the dinner and addresses the great crowd following Jesus with blunt discipleship demands: whoever does not hate family, life, and possessions cannot be his disciple; whoever does not bear his cross cannot follow. Two parables — the tower-builder and the warring king — press the necessity of counting the cost before committing. The chapter concludes with the salt sayings (vv.34-35): salt that has lost its savor is fit for nothing. Discipleship without genuine cost-counting and commitment is like tasteless salt — it has lost its essential quality.',
  'Humility, the Great Banquet, and the Cost of Discipleship',
  'ταπεινόω (tapeinōō)',
  'tapeinōō means to humble, to make low, to bring down from a high position. It is derived from tapeinos (low, humble, of low status). In Luke 14, the verb appears in the chapter''s central wisdom saying (v.11): "For whosoever exalteth himself shall be abased (tapeinōthēsetai), and he that humbleth himself (tapeinōn heauton) shall be exalted." This principle governs the entire chapter: seating at the banquet, the guest list, the response to the great supper invitation, and the posture of discipleship. True kingdom participation requires voluntary self-lowering before God and others.',
  '["Sabbath Healing of the Dropsical Man: Silence and a Silenced Opposition (vv.1-6)","Wisdom at the Feast: Humility and Eschatological Reversal (vv.7-14)","The Parable of the Great Supper: Rejection and Replacement (vv.15-24)","The Cost of Discipleship: Cross, Tower, and King (vv.25-35)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'And it came to pass, as he went into the house of one of the chief Pharisees to eat bread on the sabbath day, that they watched him.', 'Καὶ ἐγένετο ἐν τῷ ἐλθεῖν αὐτὸν εἰς οἶκόν τινος τῶν ἀρχόντων τῶν Φαρισαίων σαββάτῳ φαγεῖν ἄρτον, καὶ αὐτοὶ ἦσαν παρατηρούμενοι αὐτόν.', 'Kai egeneto en tō elthein auton eis oikon tinos tōn archontōn tōn Pharisaiōn sabbatō phagein arton, kai autoi ēsan paratēroumenoi auton.', '"Chief Pharisees" (archontōn tōn Pharisaiōn — rulers, leading members of the Pharisaic party) — the host is among the most prominent religious leaders. "They watched him" (paratēroumenoi — closely observing, scrutinizing, the word used for spying on criminals or watching for dangerous symptoms) — the dinner is a surveillance operation. Jesus enters knowing he is being watched, and he acts anyway. His healings are never a reaction to surveillance but a response to human need.', NULL),
  (2, 'And, behold, there was a certain man before him which had the dropsy.', 'καὶ ἰδοὺ ἄνθρωπός τις ἦν ὑδρωπικὸς ἔμπροσθεν αὐτοῦ.', 'kai idou anthrōpos tis ēn hudrōpikos emprosthen autou.', '"Behold" (idou) signals the narrative surprise: a sick man is present at an elite Pharisaic dinner. "Dropsy" (hudrōpikos — hydropsy, from hudōr, water) is a condition of fluid retention causing severe swelling, often a symptom of underlying organ failure (kidney or liver disease). The man''s presence may have been arranged as a test, or he may have gained access as an uninvited guest (as the sinful woman of 7:37). Either way, his need and Jesus''s response are the focus.', NULL),
  (3, 'And Jesus answering spake unto the lawyers and Pharisees, saying, Is it lawful to heal on the sabbath day?', 'καὶ ἀποκριθεὶς ὁ Ἰησοῦς εἶπεν πρὸς τοὺς νομικοὺς καὶ Φαρισαίους λέγων, Εἰ ἔξεστιν τῷ σαββάτῳ θεραπεῦσαι ἢ οὔ;', 'kai apokritheis ho Iēsous eipen pros tous nomikous kai Pharisaious legōn, Ei exestin tō sabbatō therapeusai ē ou?', '"Answering" (apokritheis) — Jesus responds to their watching with a direct question before they can formulate their trap. He places the question openly before them: "Is it lawful to heal on the sabbath day?" (Ei exestin — whether it is permissible, legally allowed). This forces them to choose between two bad options: say yes (undermining their critique), or say no (appearing merciless). Their silence (v.4) is the only way to avoid the dilemma.', NULL),
  (4, 'And they held their peace. And he took him, and healed him, and let him go;', 'καὶ οἱ ἡσύχασαν. καὶ ἐπιλαβόμενος ἰάσατο αὐτὸν καὶ ἀπέλυσεν.', 'kai hoi hēsuchazan. kai epilabomenos iasato auton kai apelusen.', '"They held their peace" (hēsuchazan — were silent, kept quiet) — strategic silence rather than principled answer. Jesus does not wait for permission or consensus. He "took him" (epilabomenos — taking hold of him, grasping him) — the physical touch of deliberate contact — "healed him" (iasato — cured him completely, aorist) — instantly — "and let him go" (apelusen — released him, dismissed him) — the word of freedom and departure. The healing is done with three rapid verbs: touch, heal, release.', NULL),
  (5, 'And answered them, saying, Which of you shall have an ass or an ox fallen into a pit, and will not straightway pull him out on the sabbath day?', 'καὶ πρὸς αὐτοὺς εἶπεν, Τίνος ὑμῶν υἱὸς ἢ βοῦς εἰς φρέαρ πεσεῖται, καὶ οὐκ εὐθέως ἀνασπάσει αὐτὸν ἐν ἡμέρᾳ τοῦ σαββάτου;', 'kai pros autous eipen, Tinos humōn huios ē bous eis phrear peseitai, kai ouk eutheōs anaspasei auton en hēmera tou sabbatou?', 'The argument a fortiori intensifies from Luke 13:15 (ox or ass loosed for watering) to a well or pit rescue. "Son or ox" — some manuscripts read "son," others "ass"; either reading makes the point stronger (a child fallen in a pit would certainly be rescued immediately). "Straightway" (eutheōs — immediately, without hesitation) — no one would wait to rescue a child or animal from a pit until after the Sabbath. The logic is irresistible: if rescue urgency overrides Sabbath for animals, how much more for a human being?', NULL),
  (6, 'And they could not answer him again to these things.', 'καὶ οὐκ ἴσχυσαν ἀνταποκριθῆναι αὐτῷ πρὸς ταῦτα.', 'kai ouk ischusan antapokrithenai autō pros tauta.', '"Could not answer" (ouk ischusan — had no power, lacked the strength/ability) "again" (antapokrithenai — to answer back, to respond in counter-argument) — a legal term for not being able to reply in a judicial dispute. Their silence is complete capitulation on the theological level. They remain personally opposed but cannot offer a rebuttal. The healing stands, the argument stands, and the Pharisees are left in wordless resentment. The pattern will repeat until the cross provides their ultimate "answer."', NULL),
  (7, 'And he put forth a parable to those which were bidden, when he marked how they chose out the chief rooms; saying unto them,', 'Ἔλεγεν δὲ πρὸς τοὺς κεκλημένους παραβολήν, ἐπέχων πῶς τὰς πρωτοκλισίας ἐξελέγοντο, λέγων πρὸς αὐτούς,', 'Elegen de pros tous keklēmenous parabolēn, epechōn pōs tas prōtoklisias exelegonto, legōn pros autous,', '"Marked" (epechōn — taking notice, observing carefully, fixing attention on) — Jesus is watching the social drama of the dinner as a teacher reads a text. "Chose out the chief rooms" (prōtoklisias exelegonto — were selecting for themselves the places of honor, the first reclining places). The reclining order at a Greco-Roman banquet directly indicated social rank. The guests'' scramble for the best positions becomes the text of the parable.', NULL),
  (8, 'When thou art bidden of any man to a wedding, sit not down in the highest room; lest a more honourable man than thou be bidden of him;', 'Ὅταν κληθῇς ὑπό τινος εἰς γάμους, μὴ κατακλιθῇς εἰς τὴν πρωτοκλισίαν, μήποτε ἐντιμότερός σου ᾖ κεκλημένος ὑπ'' αὐτοῦ,', 'Hotan klēthēs hupo tinos eis gamous, mē katakliTHēs eis tēn prōtoklisian, mēpote entimoteros sou ē keklēmenos hyp'' autou,', 'The surface level of the parable is practical wisdom: do not take the highest seat at a wedding (gamous — a wedding banquet, the most formal social occasion) lest a more honored guest arrives (entimoteros — more esteemed, more honored). This echoes Proverbs 25:6-7, which warns against presuming a place of honor before the king. But the parable is not ultimately about social strategy — it becomes a theological statement about kingdom values.', NULL),
  (9, 'And he that bade thee and him come and say to thee, Give this man place; and thou begin with shame to take the lowest room.', 'καὶ ἐλθὼν ὁ σε καὶ αὐτὸν καλέσας ἐρεῖ σοι, Δὸς τούτῳ τόπον· καὶ τότε ἄρξῃ μετὰ αἰσχύνης τὸν ἔσχατον τόπον κατέχειν.', 'kai elthōn ho se kai auton kalesas erei soi, Dos toutō topon; kai tote arxē meta aischunēs ton eschaton topon katechein.', '"With shame" (meta aischunēs — with disgrace, embarrassment, the burning feeling of public humiliation) — the person must surrender the high seat in full public view and process to the last available place. The very honor they seized becomes the occasion of maximum shame. Social aggression has produced its opposite. The parable uses the mechanics of ancient banquet culture to illustrate the spiritual dynamic of those who grasp for kingdom position.', NULL),
  (10, 'But when thou art bidden, go and sit down in the lowest room; that when he that bade thee cometh, he may say unto thee, Friend, go up higher: then shalt thou have worship in the presence of them that sit at meat with thee.', 'ἀλλ'' ὅταν κληθῇς, πορευθεὶς ἀνάπεσε εἰς τὸν ἔσχατον τόπον, ἵνα ὅταν ἔλθῃ ὁ κεκληκώς σε ἐρεῖ σοι, Φίλε, προσανάβηθι ἀνώτερον· τότε ἔσται σοι δόξα ἐνώπιον πάντων τῶν συνανακειμένων σοι.', 'all'' hotan klēthēs, poreutheis anapese eis ton eschaton topon, hina hotan elthē ho keklēkōs se erei soi, Phile, prosanabēthi anōteron; tote estai soi doxa enōpion pantōn tōn sunanakeimenōn soi.', '"Friend" (Phile — a warm address from the host) — the one who took the lowest seat is called "friend" and invited to move up. "Glory" (doxa — honor, reputation) before all the dining companions is the result of self-humbling. The reversal: the humble person receives public honor without having grasped for it; the honor comes from the host''s initiative. Theologically, this is God''s pattern of exaltation: not rewarding self-promotion but honoring genuine humility.', NULL),
  (11, 'For whosoever exalteth himself shall be abased; and he that humbleth himself shall be exalted.', 'ὅτι πᾶς ὁ ὑψῶν ἑαυτὸν ταπεινωθήσεται, καὶ ὁ ταπεινῶν ἑαυτὸν ὑψωθήσεται.', 'hoti pas ho hupsōn heauton tapeinōthēsetai, kai ho tapeinōn heauton hupsōthēsetai.', 'The parable''s theological key, repeated also in 18:14 and elsewhere (Matt 23:12; Jas 4:10; 1 Pet 5:6). "Shall be abased" (tapeinōthēsetai — divine passive: will be brought low by God) and "shall be exalted" (hupsōthēsetai — divine passive: will be lifted up by God) — both verbs are passives, indicating that God is the agent of both reversals. Human self-elevation triggers divine lowering; human self-lowering triggers divine elevation. The principle governs all kingdom relationships.', NULL),
  (12, 'Then said he also to him that bade him, When thou makest a dinner or a supper, call not thy friends, nor thy brethren, neither thy kinsmen, nor thy rich neighbours; lest they also bid thee again, and a recompence be made thee.', 'Ἔλεγεν δὲ καὶ τῷ κεκληκότι αὐτόν, Ὅταν ποιῇς ἄριστον ἢ δεῖπνον, μὴ φώνει τοὺς φίλους σου μηδὲ τοὺς ἀδελφούς σου μηδὲ τοὺς συγγενεῖς σου μηδὲ γείτονας πλουσίους, μήποτε καὶ αὐτοὶ ἀντικαλέσωσίν σε καὶ γένηται ἀνταπόδομά σοι.', 'Elegen de kai tō keklēkoti auton, Hotan poiēs ariston ē deipnon, mē phōnei tous philous sou mēde tous adelphous sou mēde tous suggeneis sou mēde geitonas plousious, mēpote kai autoi antikalesōsin se kai genētai antapodoma soi.', 'Jesus now addresses the host himself — a daring move since the host is a leading Pharisee. The prohibition is not absolute (he does not ban inviting friends forever) but challenges the social economy of reciprocal hospitality. "Lest they also bid thee again" (antikalesōsin — invite back in return) and "a recompence be made thee" (antapodoma — a return-gift, repayment). Inviting those who can repay transforms hospitality into a social investment that yields no kingdom return.', NULL),
  (13, 'But when thou makest a feast, call the poor, the maimed, the lame, the blind:', 'ἀλλ'' ὅταν δοχὴν ποιῇς, κάλει πτωχούς, ἀναπείρους, χωλούς, τυφλούς·', 'all'' hotan dochēn poiēs, kalei ptōchous, anapeirous, chōlous, tuphlous;', 'The positive instruction replaces the elite guest list with those Jesus calls "the poor, the maimed, the lame, the blind" (ptōchous, anapeirous, chōlous, tuphlous) — precisely the categories of people the great supper host gathers from the streets (v.21) and the list that defines messianic ministry (7:22; Isa 35:5-6; 61:1). Inviting these people is kingdom investment: it cannot be repaid in the present age and must be rewarded by God himself at the resurrection.', NULL),
  (14, 'And thou shalt be blessed; for they cannot recompense thee: for thou shalt be recompensed at the resurrection of the just.', 'καὶ μακάριος ἔσῃ, ὅτι οὐκ ἔχουσιν ἀνταποδοῦναί σοι· ἀνταποδοθήσεται γάρ σοι ἐν τῇ ἀναστάσει τῶν δικαίων.', 'kai makarios esē, hoti ouk echousin antapodounai soi; antapodothēsetai gar soi en tē anastasei tōn dikaiōn.', '"Thou shalt be blessed" (makarios esē — you will be blessed, in a state of divine favor) — a beatitude addressed to the host. "They cannot recompense thee" (ouk echousin antapodounai — they do not have the means to repay) — the inability of the guests to repay is the very basis of the blessing. "The resurrection of the just" (anastasei tōn dikaiōn) — a specifically Jewish phrase (Dan 12:2) for the resurrection of the righteous, which is the only occasion when divine repayment for genuine kingdom hospitality will occur.', NULL),
  (15, 'And when one of them that sat at meat with him heard these things, he said unto him, Blessed is he that shall eat bread in the kingdom of God.', 'Ἀκούσας δέ τις τῶν συνανακειμένων ταῦτα εἶπεν αὐτῷ, Μακάριος ὅστις φάγεται ἄρτον ἐν τῇ βασιλείᾳ τοῦ Θεοῦ.', 'Akousas de tis tōn sunanakeimenōn tauta eipen autō, Makarios hostis phAgetai arton en tē basileia tou Theou.', 'A dinner guest responds to the mention of the resurrection of the just with a pious exclamation: "Blessed is he that shall eat bread in the kingdom of God." This is a comfortable theological statement — a platitude about the future that deflects from the present demand. The man assumed he would be among the blessed diners in the kingdom; Jesus''s parable will gently but devastatingly question that assumption.', NULL),
  (16, 'Then said he unto him, A certain man made a great supper, and bade many:', 'ὁ δὲ εἶπεν αὐτῷ, Ἄνθρωπός τις ἐποίει δεῖπνον μέγα, καὶ ἐκάλεσεν πολλούς·', 'ho de eipen autō, Anthrōpos tis epoiei deipnon mega, kai ekalesen pollous;', '"A great supper" (deipnon mega — a great dinner, the main meal of the day) with "many" (pollous) invited — suggesting an important social event requiring advance preparation and formal invitation. In ancient Mediterranean culture, a two-stage invitation was customary: a preliminary invitation well in advance, then a same-day summons when the feast was ready. The "many" are a large group of those who had already accepted the first invitation.', NULL),
  (17, 'And sent his servant at supper time to say to them that were bidden, Come; for all things are now ready.', 'καὶ ἀπέστειλεν τὸν δοῦλον αὐτοῦ τῇ ὥρᾳ τοῦ δείπνου εἰπεῖν τοῖς κεκλημένοις, Ἔρχεσθε, ὅτι ἤδη ἕτοιμά ἐστιν.', 'kai apesteilen ton doulon autou tē hōra tou deipnou eipein tois keklēmenois, Erchesthe, hoti ēdē hetoima estin.', '"His servant" (ton doulon autou — the slave, singular) represents the messengers of God''s invitation — prophets, John, Jesus, and the apostles. "Come; for all things are now ready" (Erchesthe, hoti ēdē hetoima estin — Come! because already they are prepared) — the meal is ready; the moment of response has arrived. This second-stage summons corresponds to the present proclamation of the gospel: the kingdom is prepared; the invitation is now urgent.', NULL),
  (18, 'And they all with one consent began to make excuse. The first said unto him, I have bought a piece of ground, and I must needs go and see it: I pray thee have me excused.', 'καὶ ἤρξαντο ἀπὸ μιᾶς πάντες παραιτεῖσθαι. ὁ πρῶτος εἶπεν αὐτῷ, Ἀγρὸν ἠγόρασα καὶ ἔχω ἀνάγκην ἐξελθεῖν καὶ ἰδεῖν αὐτόν· ἐρωτῶ σε, ἔχε με παρῃτημένον.', 'kai ērxanto apo mias pantes paraitEisthai. ho prōtos eipen autō, Agron ēgorasa kai echō anankēn exelthein kai idein auton; erōtō se, eche me parētēmenon.', '"With one consent" (apo mias — from one, unanimously) — despite three different reasons, the refusal is unanimous. The first excuse: "I have bought a piece of ground" — a new land purchase that needs inspection. But buying a field sight-unseen and then inspecting after purchase is commercially senseless. The excuse is a polite lie. "I pray thee have me excused" (parētēmenon — literally: hold me as having asked to be released) — formal, legalistic language for declining an obligation.', NULL),
  (19, 'And another said, I have bought five yoke of oxen, and I go to prove them: I pray thee have me excused.', 'καὶ ἕτερος εἶπεν, Ζεύγη βοῶν ἠγόρασα πέντε καὶ πορεύομαι δοκιμάσαι αὐτά· ἐρωτῶ σε, ἔχε με παρῃτημένον.', 'kai heteros eipen, Zeugē boōn ēgorasa pente kai poreuomai dokimasai auta; erōtō se, eche me parētēmenon.', 'The second excuse: "five yoke of oxen" (zeugē boōn — pairs of oxen, ten oxen total) bought and needing testing (dokimasai — proving their pulling quality). Again the sequence is backwards: oxen are tested before purchase, not after. Five yoke suggests a large farm operation; this is a wealthy man. As with the first excuse, the economic activity is the priority over the banquet. Property and business replace relationship with the host.', NULL),
  (20, 'And another said, I have married a wife, and therefore I cannot come.', 'καὶ ἕτερος εἶπεν, Γυναῖκα ἔγημα καὶ διὰ τοῦτο οὐ δύναμαι ἐλθεῖν.', 'kai heteros eipen, Gunaika egēma kai dia touto ou dunamai elthein.', 'The third excuse is the most abrupt — no apology, no formula of regret ("I pray thee have me excused"), no pretense of politeness: "I have married a wife and therefore I cannot come." Marriage exempted a man from certain obligations (Deut 20:7; 24:5) but not from social commitments already accepted. The bluntness reveals that this man does not even feel the need to pretend; the refusal is complete and unapologetic. Luke uses this as the sharpest of the three: family attachment overrides the kingdom invitation.', NULL),
  (21, 'So that servant came, and shewed his lord these things. Then the master of the house being angry said to his servant, Go out quickly into the streets and lanes of the city, and bring in hither the poor, and the maimed, and the halt, and the blind.', 'καὶ παραγενόμενος ὁ δοῦλος ἐκεῖνος ἀπήγγειλεν τῷ κυρίῳ αὐτοῦ ταῦτα. τότε ὀργισθεὶς ὁ οἰκοδεσπότης εἶπεν τῷ δούλῳ αὐτοῦ, Ἔξελθε ταχέως εἰς τὰς πλατείας καὶ ῥύμας τῆς πόλεως, καὶ τοὺς πτωχοὺς καὶ ἀναπείρους καὶ τυφλοὺς καὶ χωλοὺς εἰσάγαγε ὧδε.', 'kai paragenomenos ho doulos ekeinos apēngeilen tō kuriō autou tauta. tote orgistheis ho oikodespotēs eipen tō doulō autou, Exelthe tacheōs eis tas plateias kai rhumas tēs poleōs, kai tous ptōchous kai anapeirous kai tuphlous kai chōlous eisagage hōde.', '"Being angry" (orgistheis — enraged, moved to indignation) — the host''s anger is righteous: the guests have broken a solemn social obligation and dishonored him publicly. His immediate response is not to close the feast but to redirect it. "Quickly" (tacheōs — at once, without delay) — the urgency of the mission to the urban poor matches the urgency of apostolic proclamation. The four categories (poor, maimed, halt, blind) are precisely those Jesus listed for the host to invite (v.13) — now the host himself does what he was commanded.', NULL),
  (22, 'And the servant said, Lord, it is done as thou hast commanded, and yet there is room.', 'καὶ εἶπεν ὁ δοῦλος, Κύριε, γέγονεν ὡς ἐπέταξας, καὶ ἔτι τόπος ἐστίν.', 'kai eipen ho doulos, Kurie, gegonen hōs epetaxas, kai eti topos estin.', '"It is done as thou hast commanded" (gegonen — it has been done, completed, the perfect tense shows a completed action with present results) — the servant has carried out the urgent city mission and the hall is filling. "Yet there is room" (eti topos estin — still place remains, the house is not yet full) — the grace of God is not exhausted by the first wave of urban outreach; the feast is large enough for more. The second mission follows.', NULL),
  (23, 'And the lord said unto the servant, Go out into the highways and hedges, and compel them to come in, that my house may be filled.', 'καὶ εἶπεν ὁ κύριος πρὸς τὸν δοῦλον, Ἔξελθε εἰς τὰς ὁδοὺς καὶ φραγμούς, καὶ ἀνάγκασον εἰσελθεῖν, ἵνα γεμισθῇ μου ὁ οἶκος.', 'kai eipen ho kurios pros ton doulon, Exelthe eis tas hodous kai phragmous, kai anankason eiselthein, hina gemisthē mou ho oikos.', '"Highways and hedges" (hodous kai phragmous — roads and fence lines, the countryside outside the city) — the Gentile world beyond the city of Israel. "Compel them to come in" (anankason eiselthein — constrain, press urgently) — not violent coercion but the urgency of pressing invitation to reluctant people who do not feel worthy to enter (cf. 24:29 where Jesus is "constrained" to stay with Emmaus disciples). "My house may be filled" — the fullness of the Gentile mission fills the house; God''s purpose cannot be frustrated by the original guests'' refusal.', NULL),
  (24, 'For I say unto you, That none of those men which were bidden shall taste of my supper.', 'λέγω γὰρ ὑμῖν ὅτι οὐδεὶς τῶν ἀνδρῶν ἐκείνων τῶν κεκλημένων γεύσεταί μου τοῦ δείπνου.', 'legō gar humin hoti oudeis tōn andrōn ekeinōn tōn keklēmenōn geusetai mou tou deipnou.', '"None of those men" (oudeis tōn andrōn ekeinōn — not one of those men) — absolute and total exclusion of the original invited guests. "Shall taste" (geusetai — will taste, experience) — the denial is complete. The shift to "I say unto you" (legō gar humin) suggests the host is now speaking as the divine voice addressing the Pharisees who are present. Those who have the first invitation — Israel''s religious establishment — will not partake in the messianic feast they declined.', NULL),
  (25, 'And there went great multitudes with him: and he turned, and said unto them,', 'Συνεπορεύοντο δὲ αὐτῷ ὄχλοι πολλοί, καὶ στραφεὶς εἶπεν πρὸς αὐτούς,', 'Suneporeunto de autō ochloi polloi, kai strapheis eipen pros autous,', 'The scene shifts from the dinner to the road. "Great multitudes" (ochloi polloi — many crowds, plural) accompany Jesus on his journey to Jerusalem. "Turned" (strapheis — turning around to face them) — a deliberate, physical redirection of attention. The crowds who follow Jesus enthusiastically need to hear what genuine discipleship costs. What follows is not encouragement but challenge: Jesus is about to test whether the large crowd is following for the right reasons.', NULL),
  (26, 'If any man come to me, and hate not his father, and mother, and wife, and children, and brethren, and sisters, yea, and his own life also, he cannot be my disciple.', 'Εἴ τις ἔρχεται πρός με καὶ οὐ μισεῖ τὸν πατέρα ἑαυτοῦ καὶ τὴν μητέρα καὶ τὴν γυναῖκα καὶ τὰ τέκνα καὶ τοὺς ἀδελφοὺς καὶ τὰς ἀδελφάς, ἔτι τε καὶ τὴν ψυχὴν ἑαυτοῦ, οὐ δύναταί μου εἶναι μαθητής.', 'Ei tis erchetai pros me kai ou misei ton patera heautou kai tēn mētera kai tēn gunaika kai ta tekna kai tous adelphous kai tas adelphas, eti te kai tēn psuchēn heautou, ou dunatai mou einai mathētēs.', '"Hate" (misei) is a Semitic comparative idiom meaning "love less by comparison" (cf. Gen 29:30-31 where Jacob "loves" Rachel and "hates" Leah, translated in meaning as "loved more" and "loved less"). Matthew 10:37 reads "love more than" — the parallel clarifies the meaning. This is not permission for literal hatred but a demand that allegiance to Jesus surpasses every other loyalty, including self (tēn psuchēn heautou — his own soul/life). Every other relationship must be secondary to discipleship.', NULL),
  (27, 'And whosoever doth not bear his cross, and come after me, cannot be my disciple.', 'ὅστις οὐ βαστάζει τὸν σταυρὸν ἑαυτοῦ καὶ ἔρχεται ὀπίσω μου, οὐ δύναταί μου εἶναι μαθητής.', 'hostis ou bastazei ton stauron heautou kai erchetai opisō mou, ou dunatai mou einai mathētēs.', '"Bear his cross" (bastazei ton stauron heautou — carries his own cross) — said to people who had seen criminals carrying their execution instruments through the streets to the place of death. The cross was a public symbol of condemned, shameful death. Jesus requires his disciples to adopt this posture voluntarily: public association with him that includes shame, rejection, and potentially death. "And come after me" (erchetai opisō mou — continues coming behind me) — the following is continuous, not a one-time act.', NULL),
  (28, 'For which of you, intending to build a tower, sitteth not down first, and counteth the cost, whether he have sufficient to finish it?', 'τίς γὰρ ἐξ ὑμῶν θέλων πύργον οἰκοδομῆσαι οὐχὶ πρῶτον καθίσας ψηφίζει τὴν δαπάνην, εἰ ἔχει εἰς ἀπαρτισμόν;', 'tis gar ex humōn thelōn purgon oikodomēsai ouchi prōton kathisas psēphizei tēn dapanēn, ei echei eis apartismon?', 'The first cost-counting parable: a tower builder. "Sitteth not down first" (prōton kathisas — first sitting down, a deliberate posture of calculation) and "counteth the cost" (psēphizei tēn dapanēn — calculates the expense, psēphizō from psēphos a voting stone, hence counting) — whether sufficient (eis apartismon — for completion). The prudent builder does not begin construction until he knows he can finish. The point: discipleship is a long-term, costly commitment; count what it will require before you begin.', NULL),
  (29, 'Lest haply, after he hath laid the foundation, and is not able to finish it, all that behold it begin to mock him,', 'ἵνα μήποτε θέντος αὐτοῦ θεμέλιον καὶ μὴ ἰσχύοντος ἐκτελέσαι, πάντες οἱ θεωροῦντες ἄρξωνται ἐμπαίζειν αὐτῷ,', 'hina mēpote thentos autou themelion kai mē ischuontos ektelesai, pantes hoi theōrountes arxōntai empaizein autō,', '"Begin to mock him" (arxōntai empaizein — begin to ridicule, jeer at) — public mockery is the consequence of abandoned construction. An unfinished tower stands as a monument to the builder''s failure of calculation. Applied to discipleship: the disciple who begins enthusiastically without counting the cost, then abandons the way under pressure, becomes an object of ridicule and brings dishonor to the name of Christ. The damage is both personal and evangelistic.', NULL),
  (30, 'Saying, This man began to build, and was not able to finish.', 'λέγοντες ὅτι Οὗτος ὁ ἄνθρωπος ἤρξατο οἰκοδομεῖν καὶ οὐκ ἴσχυσεν ἐκτελέσαι.', 'legontes hoti Houtos ho anthrōpos ērxato oikodomein kai ouk ischusen ektelesai.', '"This man began and could not finish" — the epitaph of a half-built tower and a half-formed disciple. The saying "he began but could not finish" (ēRxato...ouk ischusen ektelesai) is a pair of past tenses (aorists) describing a completed failure: the beginning happened; the finishing did not. The brevity of the comment captures the contempt of onlookers. Jesus uses this vivid social disgrace as a warning against superficial, uncalculated commitment to the kingdom.', NULL),
  (31, 'Or what king, going to make war against another king, sitteth not down first, and consulteth whether he be able with ten thousand to meet him that cometh against him with twenty thousand?', 'ἢ τίς βασιλεὺς πορευόμενος ἑτέρῳ βασιλεῖ συμβαλεῖν εἰς πόλεμον οὐχὶ καθίσας πρῶτον βουλεύσεται εἰ δυνατός ἐστιν ἐν δέκα χιλιάσιν ὑπαντῆσαι τῷ μετὰ εἴκοσι χιλιάδων ἐρχομένῳ ἐπ'' αὐτόν;', 'ē tis basileus poreuomenos heterō basilei sumbalein eis polemon ouchi kathisas prōton bouleUsetai ei dunatos estin en deka chiliasin hupantēsai tō meta eikosi chiliAdōn erchomenō ep'' auton?', 'The second parable: a king with 10,000 facing a king with 20,000. "Sitteth not down first" (prōton kathisas — the same deliberate sitting of calculation) and "consulteth" (bouleuSetai — deliberates, plans strategically, takes counsel). The odds are against him — two to one — and he must honestly assess whether his 10,000 can defeat the enemy''s 20,000. The military context raises the stakes: in war, poor calculation costs not just money but lives. Discipleship has similarly irreversible consequences.', NULL),
  (32, 'Or else, while the other is yet a great way off, he sendeth an ambassage, and desireth conditions of peace.', 'εἰ δὲ μήγε, ἔτι αὐτοῦ πόρρω ὄντος, πρεσβείαν ἀποστείλας ἐρωτᾷ τὰ πρὸς εἰρήνην.', 'ei de mēge, eti autou porrō ontos, presbeian aposteilas erōtā ta pros eirēnēn.', '"If not" — if he cannot win — the wise king sends an embassy (presbeian — ambassadors, a peace delegation) while the enemy is still far off (porrō ontos — at a distance, while there is still time). He negotiates for peace rather than inviting certain defeat. The application is striking: if you are not willing and able to pay the full cost of discipleship, it is better to honestly assess this before committing than to pursue it partway and then be overwhelmed.', NULL),
  (33, 'So likewise, whosoever he be of you that forsaketh not all that he hath, he cannot be my disciple.', 'οὕτως οὖν πᾶς ἐξ ὑμῶν ὃς οὐκ ἀποτάσσεται πᾶσιν τοῖς ἑαυτοῦ ὑπάρχουσιν, οὐ δύναταί μου εἶναι μαθητής.', 'houtōs oun pas ex humōn hos ouk apotassetai pasin tois heautou huparchousin, ou dunatai mou einai mathētēs.', '"Forsaketh not all that he hath" (ouk apotassetai pasin tois heautou huparchousin — does not renounce/say farewell to all his own possessions) — apotassetai is the word for saying a formal farewell, taking leave of, renouncing. The renunciation of "all" is the cost: not a percentage, not what is convenient, but all. This does not necessarily mean literal destitution (the disciples retained homes and boats) but means holding all things as available for the kingdom''s call. No possession can be off-limits to the lordship of Jesus.', NULL),
  (34, 'Salt is good: but if the salt have lost his savour, wherewith shall it be seasoned?', 'Καλὸν οὖν τὸ ἅλας· ἐὰν δὲ καὶ τὸ ἅλας μωρανθῇ, ἐν τίνι ἀρτυθήσεται;', 'Kalon oun to halas; ean de kai to halas mōranthē, en tini artuthēsetai?', 'The salt saying (cf. Matt 5:13; Mark 9:50) closes the discipleship discourse. "Salt is good" (Kalon to halas) — salt''s functions are indispensable: preserving, flavoring, purifying. "If the salt have lost his savour" (mōranthē — become foolish, insipid, tasteless; the word is from mōros — fool — linked to "insipid" through loss of sharp quality). How do you re-salt salt? It is an impossibility: the very substance that does the seasoning cannot itself be seasoned. Discipleship without genuine commitment is like this — it has lost its essential quality.', NULL),
  (35, 'It is neither fit for the land, nor yet for the dunghill; but men cast it out. He that hath ears to hear, let him hear.', 'οὔτε εἰς γῆν οὔτε εἰς κοπρίαν εὔθετόν ἐστιν, ἔξω βάλλουσιν αὐτό. ὁ ἔχων ὦτα ἀκούειν ἀκουέτω.', 'oute eis gēn oute eis koprian euthetOn estin, exō ballousin auto. ho echōn ōta akouein akouetō.', 'Tasteless salt is useless — not even fit as fertilizer (eis gēn — for the soil) or as a compost activator (eis koprian — for the manure heap). "Men cast it out" (exō ballousin auto — they throw it away, outside) — the final fate of the tasteless disciple. "He that hath ears to hear, let him hear" (akouetō — present imperative: keep hearing, keep listening) — the solemn formula that marks a saying of supreme importance, calling for the kind of attentive, obedient hearing that the entire chapter demanded.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 14;
